def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    class FenwickTree:
        def __init__(self, size):
            self.n = size
            self.tree = [0] * (self.n + 2)  # Using n+2 to avoid issues with 1-based indexing

        def update(self, idx, delta):
            while idx <= self.n:
                self.tree[idx] += delta
                idx += idx & -idx

        def query(self, idx):
            res = 0
            while idx > 0:
                res += self.tree[idx]
                idx -= idx & -idx
            return res

        def range_query(self, l, r):
            # l and r are 0-based indices
            return self.query(r + 1) - self.query(l)

    n = len(nums)

    def compute_depth(x):
        depth = 0
        while x != 1:
            x = bin(x).count('1')
            depth += 1
        return depth

    depths = [compute_depth(x) for x in nums]

    # Initialize Fenwick Trees for k = 0 to 5
    ft = [FenwickTree(n) for _ in range(6)]

    for i in range(n):
        d = depths[i]
        if 0 <= d <= 5:
            ft[d].update(i + 1, 1)

    answer = []
    for q in queries:
        if q[0] == 1:
            l, r, k = q[1], q[2], q[3]
            if 0 <= k <= 5:
                res = ft[k].range_query(l, r)
                answer.append(res)
            else:
                answer.append(0)
        else:
            idx, val = q[1], q[2]
            old_d = depths[idx]
            if 0 <= old_d <= 5:
                ft[old_d].update(idx + 1, -1)
            nums[idx] = val
            new_d = compute_depth(val)
            if 0 <= new_d <= 5:
                ft[new_d].update(idx + 1, 1)
            depths[idx] = new_d

    return answer
